sql:
SELECT item_id, title, acceptedAnswer
FROM content_items
WHERE item_type = 'Question' AND acceptedAnswer IS NOT NULL;

SELECT COUNT(DISTINCT p.property_id) 
FROM properties p
WHERE p.equivalentProperty IS NOT NULL AND p.deprecated = 0;

SELECT user_name, email
FROM users
WHERE role_id = 1;

SELECT DISTINCT value 
FROM property_values 
WHERE property_id = 'https://schema.org/acceptedAnswer';
